-- Select all columns
SELECT * FROM users;

-- Select specific columns
SELECT id, name, email FROM users;

-- Aliases
SELECT name AS username, email FROM users;

-- Distinct values
SELECT DISTINCT city FROM users;

-- Literal columns
SELECT name, 'Active' AS status FROM users;

-- Expressions
SELECT name, salary * 1.1 AS raised_salary FROM employees;
SELECT CONCAT(first_name, ' ', last_name) AS full_name FROM users;

-- LIMIT / OFFSET
SELECT * FROM users LIMIT 10 OFFSET 20;

-- Subquery in WHERE
SELECT * FROM products
WHERE price > (SELECT AVG(price) FROM products);

-- Subquery in FROM
SELECT dept, avg_salary
FROM (
  SELECT department AS dept, AVG(salary) AS avg_salary
  FROM employees
  GROUP BY department
) AS sub
WHERE avg_salary > 60000;

-- Subquery in SELECT
SELECT name,
  (SELECT COUNT(*) FROM orders WHERE user_id = users.id) AS order_count
FROM users;

-- EXISTS
SELECT * FROM users u
WHERE EXISTS (
  SELECT 1 FROM orders o WHERE o.user_id = u.id
);

-- ANY / ALL
SELECT * FROM products
WHERE price > ANY (SELECT price FROM products WHERE category = 'Electronics');

-- INSERT
INSERT INTO users (name, email) VALUES ('John', 'john@example.com');
INSERT INTO users (name, email) VALUES
  ('Jane', 'jane@example.com'),
  ('Bob', 'bob@example.com');
INSERT INTO archive SELECT * FROM old_users WHERE deleted = true;

-- UPDATE
UPDATE users SET email = 'new@email.com' WHERE id = 1;
UPDATE products SET price = price * 1.1 WHERE category = 'Electronics';

-- DELETE
DELETE FROM users WHERE id = 1;
DELETE FROM logs WHERE created_at < '2024-01-01';

-- TRUNCATE (remove all rows, faster than DELETE)
TRUNCATE TABLE temp_data;

-- MERGE / UPSERT (PostgreSQL)
INSERT INTO users (id, name, email)
VALUES (1, 'John', 'john@test.com')
ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name;

-- Create table
CREATE TABLE users (
  id SERIAL PRIMARY KEY,
  name VARCHAR(100) NOT NULL,
  email VARCHAR(255) UNIQUE NOT NULL,
  age INTEGER CHECK (age >= 0),
  salary DECIMAL(10,2) DEFAULT 0.00,
  status VARCHAR(20) DEFAULT 'active',
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- Constraints
NOT NULL, UNIQUE, PRIMARY KEY, FOREIGN KEY, CHECK, DEFAULT

-- Foreign key
CREATE TABLE orders (
  id SERIAL PRIMARY KEY,
  user_id INTEGER REFERENCES users(id) ON DELETE CASCADE,
  total DECIMAL(10,2),
  created_at TIMESTAMP DEFAULT NOW()
);

-- ALTER TABLE
ALTER TABLE users ADD COLUMN phone VARCHAR(20);
ALTER TABLE users DROP COLUMN phone;
ALTER TABLE users ALTER COLUMN name SET NOT NULL;
ALTER TABLE users RENAME TO customers;

-- Indexes
CREATE INDEX idx_users_email ON users(email);
CREATE UNIQUE INDEX idx_users_email ON users(email);
CREATE INDEX idx_orders_user_date ON orders(user_id, created_at);
DROP INDEX idx_users_email;

BEGIN;
UPDATE accounts SET balance = balance - 100 WHERE id = 1;
UPDATE accounts SET balance = balance + 100 WHERE id = 2;
COMMIT;

-- Rollback on error
BEGIN;
DELETE FROM orders WHERE id = 1;
-- Something went wrong...
ROLLBACK;

-- Savepoints
BEGIN;
SAVEPOINT sp1;
DELETE FROM products WHERE id = 1;
ROLLBACK TO sp1;
COMMIT;

-- Isolation levels
SET TRANSACTION ISOLATION LEVEL READ COMMITTED;
SET TRANSACTION ISOLATION LEVEL SERIALIZABLE;

